import{_ as i,o,c as a,ag as d}from"./chunks/framework.DTiDeF2Q.js";const g=JSON.parse('{"title":"นามแฝง Dig | Dotfiles (TH)","titleTemplate":":title","description":"คำสั่งสอบถาม DNS แบบสั้น ภาพรวมสำหรับ Dotfiles v0.2.495 รองรับ macOS, Linux และ WSL ผ่าน Dotfiles","frontmatter":{"title":"นามแฝง Dig | Dotfiles","description":"คำสั่งสอบถาม DNS แบบสั้น ภาพรวมสำหรับ Dotfiles v0.2.495 รองรับ macOS, Linux และ WSL ผ่าน Dotfiles","lang":"th-TH","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"นามแฝง Dig | Dotfiles preview","canonical":"/th/aliases/dig/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"นามแฝง Dig","pageType":"docs","schemaType":"WebPage","permalink":"/th/aliases/dig/"},"headers":[],"relativePath":"th/aliases/dig/index.md","filePath":"th/aliases/dig/index.md","lastUpdated":1773010926000}'),l={name:"th/aliases/dig/index.md"};function t(c,e,s,r,n,p){return o(),a("div",null,[...e[0]||(e[0]=[d('<h1 id="นามแฝง-dig" tabindex="-1">นามแฝง Dig <a class="header-anchor" href="#นามแฝง-dig" aria-label="Permalink to &quot;นามแฝง Dig&quot;">​</a></h1><p>คำสั่งสอบถาม DNS แบบสั้น</p><p>หน้านี้แนะนำกลุ่มนามแฝงหนึ่งกลุ่มและทางลัดคำสั่งทั่วไป อ่านหน้านี้ก่อนเพื่อทำความเข้าใจแบบแผนการตั้งชื่อ อินพุตที่คาดหวัง และรูปแบบการดำเนินการที่ปลอดภัย จากนั้นเปิดภาคผนวกอ้างอิงเพื่อดูรายการคำสั่งทั้งหมดและไวยากรณ์ที่แน่นอน นามแฝงเหล่านี้ลดการพิมพ์ซ้ำและรักษาพฤติกรรมเวิร์กโฟลว์ที่สม่ำเสมอบน macOS, Linux และ WSL</p><h2 id="เมื่อใดควรใช้" tabindex="-1">เมื่อใดควรใช้ <a class="header-anchor" href="#เมื่อใดควรใช้" aria-label="Permalink to &quot;เมื่อใดควรใช้&quot;">​</a></h2><p>ใช้หน้านี้ก่อนการทำงานเชลล์ประจำวันเมื่อคุณต้องการรูปแบบคำสั่งที่คาดเดาได้</p><h2 id="สิ่งที่รวมอยู่" tabindex="-1">สิ่งที่รวมอยู่ <a class="header-anchor" href="#สิ่งที่รวมอยู่" aria-label="Permalink to &quot;สิ่งที่รวมอยู่&quot;">​</a></h2><ul><li>นามแฝง: 10</li><li>ฟังก์ชันตัวช่วย: 0</li><li>ไฟล์ต้นฉบับ: 1</li></ul><h2 id="ตัวอย่างสั้น" tabindex="-1">ตัวอย่างสั้น <a class="header-anchor" href="#ตัวอย่างสั้น" aria-label="Permalink to &quot;ตัวอย่างสั้น&quot;">​</a></h2><ul><li><code>d</code> → <code>dig</code></li><li><code>d4</code> → <code>dig +short -4</code></li><li><code>d6</code> → <code>dig +short -6</code></li><li><code>dga</code> → <code>dig +all ANY</code></li><li><code>dgs</code> → <code>dig +short</code></li><li><code>digg</code> → <code>dig @8.8.8.8 +nocmd any +multiline +noall +answer</code></li><li><code>ip4</code> → <code>dig +short myip.opendns.com @resolver1.opendns.com -4</code></li><li><code>ip6</code> → <code>dig -6 AAAA +short myip.opendns.com. @resolver1.opendns.com.</code></li><li><code>ips</code> → <code>ip4; ip6</code></li><li><code>wip</code> → <code>dig +short myip.opendns.com @resolver1.opendns.com</code></li></ul><h2 id="ขั้นตอนถัดไป" tabindex="-1">ขั้นตอนถัดไป <a class="header-anchor" href="#ขั้นตอนถัดไป" aria-label="Permalink to &quot;ขั้นตอนถัดไป&quot;">​</a></h2><p>เปิดรายการทั้งหมด:</p>',11)])])}const m=i(l,[["render",t]]);export{g as __pageData,m as default};
